#include <iostream>
#include <string>
#include <string_view>

class Animal
{
    std::string m_name;

public:
    Animal(const std::string& name)
        : m_name{name}
    {
    }

    const std::string& getName() const { return m_name; }

    std::string_view speak() const
    {
        return "...";
    }
};

class Dog : public Animal
{
public:
    Dog(const std::string& name)
        : Animal{name}
    {
    }

    std::string_view speak() const
    {
        return "Woof";
    }
};

int main()
{
    std::string name{};
    std::cin >> name;

    Dog dog{name};

    std::cout << "Direct: " << dog.getName() << " says " << dog.speak() << '\n';

    const Animal& ref{dog};
    std::cout << "Via ref: " << ref.getName() << " says " << ref.speak() << '\n';

    const Animal* ptr{&dog};
    std::cout << "Via ptr: " << ptr->getName() << " says " << ptr->speak() << '\n';

    return 0;
}

