#include <iostream>
#include <string>

class Shape
{
    std::string m_name;

public:
    Shape(const std::string& name)
        : m_name{name}
    {
    }

    const std::string& getName() const { return m_name; }

    std::string describe() const
    {
        return m_name + ": generic shape";
    }
};

class Circle : public Shape
{
    double m_radius{};

public:
    Circle(const std::string& name, double radius)
        : Shape{name}
        , m_radius{radius}
    {
    }

    std::string describe() const
    {
        return getName() + " r=" + std::to_string(m_radius);
    }
};

void report(const Shape& s)
{
    std::cout << "Report: " << s.describe() << '\n';
}

int main()
{
    std::string name{};
    double radius{};
    std::cin >> name >> radius;

    Circle circle{name, radius};

    std::cout << "Circle: " << circle.describe() << '\n';
    report(circle);
    std::cout << "Direct: " << circle.describe() << '\n';

    return 0;
}
